const args = []
if (params.left   > 0) args.push('-gravity', 'West',  '-background', 'none', '-splice', params.left   + 'x0')
if (params.right  > 0) args.push('-gravity', 'East',  '-background', 'none', '-splice', params.right  + 'x0')
if (params.top    > 0) args.push('-gravity', 'North', '-background', 'none', '-splice', '0x' + params.top)
if (params.bottom > 0) args.push('-gravity', 'South', '-background', 'none', '-splice', '0x' + params.bottom)
if (args.length > 0)   args.push('-gravity', 'NorthWest')
return args
